# Monthly upgrade window report summary

from collections import defaultdict

def generate_monthly_summary(window_records: list) -> dict:
    by_category = defaultdict(lambda: {"total": 0, "rollbacks": 0, "postponed": 0})

    for record in window_records:
        cat = record["dependency_category"]
        by_category[cat]["total"] += 1
        if record["outcome"] == "rollback":
            by_category[cat]["rollbacks"] += 1
        if record["outcome"] == "postponed":
            by_category[cat]["postponed"] += 1

    summary = {}
    for cat, counts in by_category.items():
        total = counts["total"]
        summary[cat] = {
            "total_windows": total,
            "rollback_rate": round(counts["rollbacks"] / total * 100, 1) if total else 0,
            "postpone_rate": round(counts["postponed"] / total * 100, 1) if total else 0,
        }
    return summary

# If llm_sdk rollback rate > 20%, the golden prompt comparison
# pre-check needs stricter thresholds or more prompts covering
# the breaking-change surface area of recent SDK updates.
